import { cssPrefix, cssThumbnailPrefix } from "./utils.js";
import { Thumbnail } from "./Thumbnail.js";
import { defaultThumbnailsProps, useThumbnailsProps } from "./props.js";

function isHorizontal(position: ReturnType<typeof useThumbnailsProps>["position"]) {
    return ["top", "bottom"].includes(position);
}

function boxSize(thumbnails: ReturnType<typeof useThumbnailsProps>, dimension: number, includeGap?: boolean) {
    return dimension + 2 * (thumbnails.border + thumbnails.padding) + (includeGap ? thumbnails.gap : 0);
}

export type ThumbnailsTrackProps = {
    visible: boolean;
    containerRef: React.RefObject<HTMLDivElement>;
};

export function ThumbnailsTrack({ visible, containerRef }: ThumbnailsTrackProps) {
    const track = React.useRef<HTMLDivElement | null>(null);

    const { carousel, styles } = useLightboxProps();
    const { slides, globalIndex, animation } = useLightboxState();
    const { publish, subscribe } = useEvents();
    const isRTL = useRTL();

    const thumbnails = useThumbnailsProps();
    const { position, width, height, border, borderRadius, padding, gap, vignette } = thumbnails;

    const index = globalIndex;
    const animationDuration = animation?.duration || 0;
    const offset = (animationDuration > 0 && animation?.increment) || 0;

    const { prepareAnimation } = useAnimation<number>(track, (snapshot) => ({
        keyframes: isHorizontal(position)
            ? [
                  {
                      transform: `translateX(${
                          (isRTL ? -1 : 1) * boxSize(thumbnails, width, true) * offset + snapshot
                      }px)`,
                  },
                  { transform: "translateX(0)" },
              ]
            : [
                  {
                      transform: `translateY(${boxSize(thumbnails, height, true) * offset + snapshot}px)`,
                  },
                  { transform: "translateY(0)" },
              ],
        duration: animationDuration,
        easing: animation?.easing,
    }));

    const handleControllerSwipe = useEventCallback(() => {
        let animationOffset = 0;
        if (containerRef.current && track.current) {
            const containerRect = containerRef.current.getBoundingClientRect();
            const trackRect = track.current.getBoundingClientRect();
            animationOffset = isHorizontal(position)
                ? trackRect.left - containerRect.left - (containerRect.width - trackRect.width) / 2
                : trackRect.top - containerRect.top - (containerRect.height - trackRect.height) / 2;
        }

        prepareAnimation(animationOffset);
    });

    React.useEffect(() => cleanup(subscribe(ACTION_SWIPE, handleControllerSwipe)), [subscribe, handleControllerSwipe]);

    const { finite } = carousel;
    const preload = Math.min(carousel.preload, Math.floor(slides.length / 2));

    const items: { slide: Slide | null; index: number; placeholder?: boolean }[] = [];

    if (hasSlides(slides)) {
        if (offset < 0) {
            for (let i = index - preload + offset; i < index - preload; i += 1) {
                items.push({ slide: null, index: i, placeholder: true });
            }
        }

        for (let i = index - preload - Math.max(offset, 0); i < index; i += 1) {
            if (!(finite && i < 0)) {
                items.push({ slide: getSlide(slides, i), index: i });
            } else {
                items.push({ slide: null, index: i, placeholder: true });
            }
        }

        items.push({ slide: getSlide(slides, index), index });

        for (let i = index + 1; i <= index + preload - Math.min(offset, 0); i += 1) {
            if (!finite || i <= slides.length - 1) {
                items.push({ slide: getSlide(slides, i), index: i });
            } else {
                items.push({ slide: null, index: i, placeholder: true });
            }
        }

        if (offset > 0) {
            for (let i = index + preload + 1; i <= index + preload + offset; i += 1) {
                items.push({ slide: null, index: i, placeholder: true });
            }
        }
    }

    const handleClick = (slideIndex: number) => () => {
        if (slideIndex > index) {
            publish(ACTION_NEXT, { count: slideIndex - index });
        } else if (slideIndex < index) {
            publish(ACTION_PREV, { count: index - slideIndex });
        }
    };

    return (
        <div
            className={clsx(cssClass(cssPrefix("container")), cssClass(CLASS_FLEX_CENTER))}
            style={{
                ...(!visible ? { display: "none" } : null),
                ...(width !== defaultThumbnailsProps.width
                    ? { [cssVar(cssThumbnailPrefix("width"))]: `${boxSize(thumbnails, width)}px` }
                    : null),
                ...(height !== defaultThumbnailsProps.height
                    ? { [cssVar(cssThumbnailPrefix("height"))]: `${boxSize(thumbnails, height)}px` }
                    : null),
                ...(border !== defaultThumbnailsProps.border
                    ? { [cssVar(cssThumbnailPrefix("border"))]: `${border}px` }
                    : null),
                ...(borderRadius !== defaultThumbnailsProps.borderRadius
                    ? { [cssVar(cssThumbnailPrefix("border_radius"))]: `${borderRadius}px` }
                    : null),
                ...(padding !== defaultThumbnailsProps.padding
                    ? { [cssVar(cssThumbnailPrefix("padding"))]: `${padding}px` }
                    : null),
                ...(gap !== defaultThumbnailsProps.gap ? { [cssVar(cssThumbnailPrefix("gap"))]: `${gap}px` } : null),
                ...styles.thumbnailsContainer,
            }}
        >
            <nav
                ref={track}
                style={styles.thumbnailsTrack}
                className={clsx(cssClass(cssPrefix("track")), cssClass(CLASS_FLEX_CENTER))}
            >
                {items.map(({ slide, index: slideIndex, placeholder }) => {
                    const fadeAnimationDuration = animationDuration / Math.abs(offset || 1);

                    const fadeIn =
                        (offset > 0 && slideIndex > index + preload - offset && slideIndex <= index + preload) ||
                        (offset < 0 && slideIndex < index - preload - offset && slideIndex >= index - preload)
                            ? {
                                  duration: fadeAnimationDuration,
                                  delay:
                                      ((offset > 0
                                          ? slideIndex - (index + preload - offset)
                                          : index - preload - offset - slideIndex) -
                                          1) *
                                      fadeAnimationDuration,
                              }
                            : undefined;

                    const fadeOut =
                        (offset > 0 && slideIndex < index - preload) || (offset < 0 && slideIndex > index + preload)
                            ? {
                                  duration: fadeAnimationDuration,
                                  delay:
                                      (offset > 0
                                          ? offset - (index - preload - slideIndex)
                                          : -offset - (slideIndex - (index + preload))) * fadeAnimationDuration,
                              }
                            : undefined;

                    return (
                        <Thumbnail
                            key={slideIndex}
                            slide={slide}
                            active={slideIndex === index}
                            fadeIn={fadeIn}
                            fadeOut={fadeOut}
                            placeholder={Boolean(placeholder)}
                            onClick={handleClick(slideIndex)}
                        />
                    );
                })}
            </nav>
            {vignette && <div className={cssClass(cssPrefix("vignette"))} />}
        </div>
    );
}
import * as React from "react";
import { act, render, screen } from "@testing-library/react";

import { clickButton, expectCurrentImageToBe, expectToContainButton, lightbox } from "../utils.js";
import { Fullscreen, Thumbnails, Video } from "../../../src/plugins/index.js";
import { LightboxExternalProps } from "../../../src/index.js";

function renderLightbox(props?: LightboxExternalProps) {
    return render(
        lightbox({
            slides: [{ src: "image1" }, { src: "image2" }, { src: "image3" }],
            plugins: [Thumbnails],
            ...props,
        })
    );
}

function queryThumbnails() {
    return screen
        .queryAllByRole("button")
        .filter((el) => el.className.split(" ").includes("yarl__thumbnails_thumbnail"));
}

function clickThumbnail(image: string) {
    act(() => {
        queryThumbnails()
            .find((el) => Boolean(el.querySelector(`img[src='${image}']`)))!
            .click();
    });
}

function expectThumbnails(visible = true) {
    expect(queryThumbnails().length > 0).toBe(visible);
}

function expectNavigation() {
    clickButton("Next");
    clickButton("Previous");
    expectThumbnails();
}

describe("Thumbnails", () => {
    it("renders without crashing", () => {
        renderLightbox();
        expectNavigation();
    });

    it("supports thumbnails toggle button", () => {
        renderLightbox({ thumbnails: { showToggle: true } });
        expectThumbnails();

        clickButton("Hide thumbnails");
        expectThumbnails(false);

        clickButton("Show thumbnails");
        expectThumbnails();
    });

    it("supports thumbnails navigation", () => {
        renderLightbox({ carousel: { preload: 1 } });
        expectCurrentImageToBe("image1");

        clickThumbnail("image2");
        expectCurrentImageToBe("image2");

        clickThumbnail("image1");
        expectCurrentImageToBe("image1");
    });

    it("supports thumbnails position", () => {
        renderLightbox({ thumbnails: { position: "top" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "bottom" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "start" } });
        expectNavigation();

        renderLightbox({ thumbnails: { position: "end" } });
        expectNavigation();
    });

    it("works with Fullscreen", () => {
        // Fullscreen plugin must be listed first
        renderLightbox({ plugins: [Fullscreen, Thumbnails] });
        expectThumbnails();
    });

    it("supports custom thumbnails button", () => {
        renderLightbox({
            thumbnails: { showToggle: true },
            render: { buttonThumbnails: () => React.createElement("button", { type: "button" }, "Custom button") },
        });
        expectToContainButton("Custom button");
    });

    it("supports thumbnails customization", () => {
        renderLightbox({ thumbnails: { border: 2, borderRadius: 5, width: 60, height: 40, padding: 10, gap: 10 } });
        expectThumbnails();
    });

    it("supports finite carousel", () => {
        renderLightbox({ carousel: { finite: true } });
        expectThumbnails();

        clickButton("Next");
        expectThumbnails();
    });

    it("supports video thumbnails", () => {
        renderLightbox({
            slides: [{ type: "video", poster: "poster", sources: [{ src: "video", type: "video/mp4" }] }],
            plugins: [Thumbnails, Video],
        });
        clickThumbnail("poster");
    });

    it("supports unknown slide types", () => {
        // @ts-expect-error
        renderLightbox({ slides: [{ type: "custom" }] });
        expectThumbnails();
    });

    it("supports custom thumbnails", () => {
        renderLightbox({ render: { thumbnail: () => React.createElement("img", { src: "custom" }) } });
        clickThumbnail("custom");
    });
});
import { act, fireEvent, render, screen } from "@testing-library/react";

import { expectCurrentImageToBe, findCurrentImage, findCurrentSlide, lightbox, withFakeTimers } from "./utils.js";

const fireWheelEvent = (element: Element, options: { deltaX?: number; deltaY?: number; ctrlKey?: boolean }) => {
    // noinspection TypeScriptValidateJSTypes
    fireEvent.wheel(element, options);
};

describe("Lightbox", () => {
    it("respects open prop", () => {
        const { rerender } = render(lightbox({ open: false }));
        expect(screen.queryByRole("presentation")).not.toBeInTheDocument();

        rerender(lightbox());
        expect(screen.getByRole("presentation")).toBeInTheDocument();
    });

    it("presents basic controls", () => {
        render(lightbox());

        expect(screen.queryByRole("presentation")).toBeInTheDocument();
        expect(screen.queryByLabelText("Close")).toBeInTheDocument();
        expect(screen.queryByLabelText("Previous")).toBeInTheDocument();
        expect(screen.queryByLabelText("Next")).toBeInTheDocument();
    });

    it("respects index prop", () => {
        for (let i = 0; i < 3; i += 1) {
            const { unmount } = render(
                lightbox({
                    slides: [{ src: "image1" }, { src: "image2" }, { src: "image3" }],
                    index: i,
                    carousel: { preload: 1 },
                })
            );
            expect(findCurrentImage()).toContain(`image${i + 1}`);
            unmount();
        }
    });

    it("provides navigation buttons", () => {
        render(lightbox({ slides: [{ src: "image1" }, { src: "image2" }, { src: "image3" }] }));

        expectCurrentImageToBe("image1");

        act(() => {
            screen.getByLabelText("Next").click();
        });

        expectCurrentImageToBe("image2");

        act(() => {
            screen.getByLabelText("Previous").click();
        });
        act(() => {
            screen.getByLabelText("Previous").click();
        });

        expectCurrentImageToBe("image3");
    });

    it("supports wheel navigation", () =>
        withFakeTimers(({ runAllTimers }) => {
            render(
                lightbox({
                    slides: [{ src: "image1" }, { src: "image2" }, { src: "image3" }],
                    carousel: { finite: true },
                })
            );

            expectCurrentImageToBe("image1");

            const slide = findCurrentSlide()!;

            // not a swipe
            runAllTimers();
            fireWheelEvent(slide, { deltaX: 1 });
            fireWheelEvent(slide, { ctrlKey: true });
            fireWheelEvent(slide, { deltaX: 100, deltaY: 200 });
            fireWheelEvent(slide, { deltaX: 500, deltaY: 1000 });
            runAllTimers();
            expectCurrentImageToBe("image1");

            // invalid swipe
            runAllTimers();
            fireWheelEvent(slide, { deltaX: -100 });
            fireWheelEvent(slide, { deltaX: -1000 });
            fireWheelEvent(slide, { deltaX: -1000 });
            runAllTimers();
            expectCurrentImageToBe("image1");

            // insufficient swipe
            runAllTimers();
            fireWheelEvent(slide, { deltaX: 50 });
            fireWheelEvent(slide, { deltaX: 100 });
            runAllTimers();
            expectCurrentImageToBe("image1");

            // valid swipe
            fireWheelEvent(slide, { deltaX: 10 });
            fireWheelEvent(slide, { deltaX: 20 });
            fireWheelEvent(slide, { deltaX: 30 });
            fireWheelEvent(slide, { deltaX: 100 });
            fireWheelEvent(slide, { deltaX: 300 });
            fireWheelEvent(slide, { deltaX: 100 });
            runAllTimers();
            fireWheelEvent(slide, { deltaX: 50 });
            expectCurrentImageToBe("image2");
        }));
});

